import { Search, Bell, HelpCircle, ChevronRight, Sparkles, LogOut, Check } from "lucide-react";
import { DsButton } from "@/shared/design-system/components";

// Simple Tenant Context
interface TenantContextType {
  tenantId: string;
  setTenantId: (id: string) => void;
  tenantName: string;
}

const TenantContext = createContext<TenantContextType>({
  tenantId: "tenant-spbe",
  setTenantId: () => {},
  tenantName: "SPBE Pemerintah RI"
});

export const useTenant = () => useContext(TenantContext);

export function WorkspaceLayoutProvider({ children }: { children: React.ReactNode }) {
  const [tenantId, setTenantId] = useState("tenant-spbe");
  const pathname = usePathname();

  // Mapping tenant codes to names
  const tenantName = tenantId === "tenant-spbe" ? "SPBE Pemerintah RI" : "Kementerian Keuangan";

  // Derive breadcrumbs from path
  const getBreadcrumbs = () => {
    const parts = pathname.split("/").filter((x) => x);
    if (parts.length === 0) return [{ name: "Dashboard", href: "/dashboard" }];
    return parts.map((part, index) => {
      const href = "/" + parts.slice(0, index + 1).join("/");
      const name = part.charAt(0).toUpperCase() + part.slice(1).replace("-", " ");
      return { name, href };
    });
  };

  const breadcrumbs = getBreadcrumbs();

